/* 
  Algorithm: Permutation Ranking & Unranking (Lehmer code)
  1) Rank each given perm into [0..n!-1], mark it found.
  2) Locate the missing rank, then unrank to produce the missing perm.
*/
#include <bits/stdc++.h>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    cin >> n;
    // Precompute factorials up to n!
    vector<int> fact(n+1, 1);
    for(int i = 1; i <= n; i++){
        fact[i] = fact[i-1] * i;
    }

    int total = fact[n];
    // found[i]==1 iff rank i has been read
    vector<char> found(total, 0);

    string s;
    // For each of the (n! - 1) input permutations
    for(int t = 0; t < total - 1; t++){
        cin >> s;
        // Rank this permutation via Lehmer code
        vector<char> used(n, 0);
        int rank = 0;
        for(int i = 0; i < n; i++){
            int d = s[i] - '0';
            int cntSmaller = 0;
            // Count how many unused digits < d
            for(int x = 0; x < d; x++){
                if(!used[x]) cntSmaller++;
            }
            rank += cntSmaller * fact[n-1-i];
            used[d] = 1;
        }
        found[rank] = 1;
    }

    // Find the missing rank
    int missingRank = -1;
    for(int i = 0; i < total; i++){
        if(!found[i]){
            missingRank = i;
            break;
        }
    }

    // Unrank the missing permutation
    vector<int> avail(n);
    iota(avail.begin(), avail.end(), 0);
    string ans;
    ans.reserve(n);
    int r = missingRank;
    for(int i = 0; i < n; i++){
        int block = r / fact[n-1-i];
        ans.push_back(char('0' + avail[block]));
        avail.erase(avail.begin() + block);
        r %= fact[n-1-i];
    }

    // Output the missing account
    cout << ans << "\n";
    return 0;
}

